root.js-content:
stp.writeLog("Begin: ActionReminder");

var GetTxId = stp.getValue("/Document/ActnRmndr/TxId","Id");
var bu=stp.getTSUUnitCode();
var fld_list = stp.addFieldList(null,"C_MAIN_REF");    
var sql_condition = stp.addSQLCondition(null,"TSU_TID",GetTxId[0]);
sql_condition     = stp.addSQLCondition(sql_condition,"C_UNIT_CODE",bu); 
sql_condition     = stp.addSQLCondition(sql_condition,"C_TRX_STATUS","M");
var result = stp.executeQuery("TSUM_MASTER",fld_list,sql_condition);
var mainRef = stp.getDBFieldValue(result,"C_MAIN_REF");
stp.writeLog("mainRef="+mainRef);
stp.updateFieldValue("","C_MAIN_REF",mainRef);
stp.updateFieldValue("/root/domData","C_TRX_REF",mainRef);


var TSU_REQ_ACT_TP = stp.getValue("/Document/ActnRmndr/PdgReqForActn","Tp");
stp.writeLog("Request Action Type: "+TSU_REQ_ACT_TP[0]);
if ( TSU_REQ_ACT_TP[0]== undefined)
{
	stp.updateFieldValue("/root/domData","TSUR2_PDG_REQ_ACT","EMPT");	
	stp.updateFieldValue("/root/domData","TSU_PDG_REQ_ACTDES","");
	stp.setNodeAttribute("/root/domData/TSU_PDG_REQ_ACTDES");
}

var OurBIC=stp.getTSUBIC();

stp.writeLog("ourBIC="+OurBIC);

var REF = stp.getValue("/Document/ActnRmndr/UsrTxRef","Id");
var BIC = stp.getValue("/Document/ActnRmndr/UsrTxRef/IdIssr","BIC");

var BIC1 = stp.compareString(BIC[0],OurBIC);
var BIC2 = stp.compareString(BIC[1],OurBIC);
stp.writeLog("BIC1--------------------" +BIC1);
stp.writeLog("BIC2--------------------" +BIC2);

if(BIC1 == "true")
{
    stp.writeLog(" -----------------------------------------------------");
    stp.updateFieldValue("TSU_OUR_BIC",BIC[0]);
    stp.updateFieldValue("TSU_OUR_REF",REF[0]);
    stp.updateFieldValue("TSU_THEIR_REF",REF[1]);
    stp.updateFieldValue("TSU_THEIR_BIC",BIC[1]);	
}
if(BIC2 == "true")
{
	stp.writeLog(" ----------------------------------------------------");
	stp.updateFieldValue("TSU_OUR_BIC",BIC[1]);
	stp.updateFieldValue("TSU_OUR_REF",REF[1]);
	stp.updateFieldValue("TSU_THEIR_REF",REF[0]);
	stp.updateFieldValue("TSU_THEIR_BIC",BIC[0]);
}
stp.setAutoProcess(true); 
stp.setFunc("R2ActionReminder");
stp.writeLog("End: Assign function ActionReminder");
